package services

import (
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"
)

var blockedPrefixes = []string{
	"http://169.254.",
	"http://10.",
	"http://172.16.",
	"http://192.168.",
	"http://127.",
	"http://localhost",
}

type ProxyService struct {
	Client *http.Client
}

func NewProxyService() *ProxyService {
	return &ProxyService{
		Client: &http.Client{
			Timeout: 30 * time.Second,
		},
	}
}

func (s *ProxyService) FetchURL(targetURL string) ([]byte, error) {
	// Validate URL scheme
	parsed, err := url.Parse(targetURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL: %w", err)
	}

	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return nil, fmt.Errorf("only http/https schemes allowed")
	}

	// Block known internal IP prefixes
	lowerURL := strings.ToLower(targetURL)
	for _, prefix := range blockedPrefixes {
		if strings.HasPrefix(lowerURL, prefix) {
			return nil, fmt.Errorf("internal addresses are blocked")
		}
	}

	// Vulnerability: DNS rebinding bypass - the hostname is checked at
	// request time but DNS can resolve to an internal IP after the check.
	// Also: the blocklist is incomplete (missing IPv6, 0.0.0.0, decimal
	// IP notation like http://2130706433, and https:// variants).
	resp, err := s.Client.Get(targetURL)
	if err != nil {
		return nil, fmt.Errorf("fetch failed: %w", err)
	}
	defer resp.Body.Close()

	return io.ReadAll(resp.Body)
}

func (s *ProxyService) IsInternalIP(host string) bool {
	ips, err := net.LookupIP(host)
	if err != nil {
		return false
	}

	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() {
			return true
		}
	}
	return false
}
